import { useState, useEffect } from "react";
import { NavLink, useLocation } from "react-router-dom";

const links = [
  { to: "/",        label: "Home",            icon: "≡ƒÅá" },
  { to: "/chat",    label: "Symptom Checker", icon: "≡ƒ⌐║" },
  { to: "/diseases",label: "Diseases",        icon: "≡ƒôÜ" },
  { to: "/myths",   label: "Myth Buster",     icon: "≡ƒö¼" },
  { to: "/history", label: "History",         icon: "≡ƒÆ¼" },
  { to: "/model",   label: "Model Stats",     icon: "≡ƒñû" },
  { to: "/about",   label: "About",           icon: "≡ƒæÑ" },
];

export default function Navbar() {
  const [scrolled, setScrolled]   = useState(false);
  const [menuOpen, setMenuOpen]   = useState(false);
  const location                  = useLocation();

  useEffect(() => {
    const handler = () => setScrolled(window.scrollY > 20);
    window.addEventListener("scroll", handler);
    return () => window.removeEventListener("scroll", handler);
  }, []);

  useEffect(() => setMenuOpen(false), [location]);

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Outfit:wght@500;600;700&family=Playfair+Display:wght@700&display=swap');
        .nav-link {
          display:flex; align-items:center; gap:5px;
          padding:7px 13px; border-radius:50px;
          font-size:13px; font-weight:600;
          color:#4a7b74; text-decoration:none;
          transition:all 0.2s ease;
          font-family:'Outfit',sans-serif;
          white-space:nowrap;
        }
        .nav-link:hover  { background:rgba(13,148,136,0.08); color:#0d9488; }
        .nav-link.active { background:rgba(13,148,136,0.12); color:#0d9488; }
        .nav-cta {
          background:linear-gradient(135deg,#0d9488,#0891b2);
          color:white !important; padding:8px 18px; border-radius:50px;
          font-size:13px; font-weight:700; text-decoration:none;
          transition:all 0.2s ease; font-family:'Outfit',sans-serif;
          box-shadow:0 4px 14px rgba(13,148,136,0.3); white-space:nowrap;
        }
        .nav-cta:hover { transform:translateY(-2px); box-shadow:0 8px 20px rgba(13,148,136,0.4); }
        @media(max-width:900px){ .desktop-links{ display:none !important; } .hamburger{ display:flex !important; } }
      `}</style>

      <nav style={{
        position:"fixed", top:0, left:0, right:0, zIndex:999,
        background: scrolled ? "rgba(255,255,255,0.96)" : "rgba(240,247,244,0.92)",
        backdropFilter:"blur(12px)",
        borderBottom: scrolled ? "1px solid #d1ede5" : "1px solid transparent",
        boxShadow: scrolled ? "0 4px 20px rgba(0,0,0,0.06)" : "none",
        transition:"all 0.3s ease",
        fontFamily:"'Outfit',sans-serif",
      }}>
        <div style={{ maxWidth:"1300px", margin:"0 auto", padding:"10px 20px", display:"flex", alignItems:"center", justifyContent:"space-between", gap:"12px" }}>

          {/* Logo */}
          <NavLink to="/" style={{ textDecoration:"none", display:"flex", alignItems:"center", gap:"8px", flexShrink:0 }}>
            <div style={{ width:"36px", height:"36px", background:"linear-gradient(135deg,#0d9488,#0891b2)", borderRadius:"10px", display:"flex", alignItems:"center", justifyContent:"center", fontSize:"17px" }}>≡ƒÅÑ</div>
            <div>
              <div style={{ fontFamily:"'Playfair Display',serif", fontSize:"15px", fontWeight:"700", color:"#0a2e29", lineHeight:1.1 }}>AI Health</div>
              <div style={{ fontSize:"9px", fontWeight:"600", color:"#0d9488", letterSpacing:"1px", textTransform:"uppercase" }}>Chatbot</div>
            </div>
          </NavLink>

          {/* Desktop links */}
          <div className="desktop-links" style={{ display:"flex", alignItems:"center", gap:"2px", flex:1, justifyContent:"center" }}>
            {links.map(l => (
              <NavLink key={l.to} to={l.to} end={l.to==="/"} className={({isActive})=>`nav-link${isActive?" active":""}`}>
                <span style={{ fontSize:"13px" }}>{l.icon}</span>
                {l.label}
              </NavLink>
            ))}
          </div>

          {/* Right side */}
          <div className="desktop-links" style={{ display:"flex", alignItems:"center", gap:"10px", flexShrink:0 }}>
            <div style={{ fontSize:"11px", fontWeight:"700", color:"#dc2626", background:"#fff5f5", border:"1px solid #fecaca", borderRadius:"50px", padding:"4px 10px", whiteSpace:"nowrap" }}>
              ≡ƒåÿ 108
            </div>
            <NavLink to="/chat" className="nav-cta">≡ƒ⌐║ Check Now</NavLink>
          </div>

          {/* Hamburger */}
          <button className="hamburger" onClick={()=>setMenuOpen(!menuOpen)} style={{ background:"none", border:"none", cursor:"pointer", fontSize:"22px", color:"#0d9488", display:"none", flexShrink:0 }}>
            {menuOpen ? "Γ£ò" : "Γÿ░"}
          </button>
        </div>

        {/* Mobile menu */}
        {menuOpen && (
          <div style={{ background:"white", borderTop:"1px solid #e2f2ee", padding:"12px 20px", display:"flex", flexDirection:"column", gap:"6px" }}>
            {links.map(l => (
              <NavLink key={l.to} to={l.to} end={l.to==="/"} className={({isActive})=>`nav-link${isActive?" active":""}`} style={{ justifyContent:"flex-start" }}>
                {l.icon} {l.label}
              </NavLink>
            ))}
            <NavLink to="/chat" className="nav-cta" style={{ textAlign:"center", marginTop:"8px" }}>≡ƒ⌐║ Check Symptoms</NavLink>
          </div>
        )}
      </nav>
    </>
  );
}
